const SponStencilDesc *spon_get_stencil(SponStencilId id) {
  const SponBankShard *s = find_shard(id);
  if (!s) return NULL;
  return &s->stencils[id - s->first];
}

const unsigned char *spon_stencil_data(SponStencilId id) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->size == 0) return NULL;
  return s->data + f->offset;
}

const SponEndpointDesc *spon_stencil_endpoints(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_endpoints == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_endpoints;
  return s->endpoints + f->endpoint_start;
}

const SponLocationDesc *spon_stencil_locations(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_endpoints == 0) { if (out_n) *out_n = 0; return NULL; }
  uint32_t first = 0xffffffffu;
  uint32_t last = 0;
  const SponEndpointDesc *eps = s->endpoints + f->endpoint_start;
  for (uint32_t i = 0; i < f->n_endpoints; i++) {
    if (eps[i].n_locations == 0) continue;
    if (eps[i].location_start < first) first = eps[i].location_start;
    if (eps[i].location_start + eps[i].n_locations > last) last = eps[i].location_start + eps[i].n_locations;
  }
  if (first == 0xffffffffu || last <= first) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = last - first;
  return s->locations + first;
}

